import { Component, h, Prop, Event, EventEmitter } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

/**
 * @deprecated Use `wdpr-tooltip` instead. `wdpr-tooltip-icon` will be removed in a future major release.
 */
@Component({
  tag: 'wdpr-tooltip-icon',
  shadow: true,
})

export class WdprTooltipIcon {
  componentWillLoad() {
    console.warn(
      'The `wdpr-tooltip-icon` component is deprecated and will be removed in a future major release. Please use `wdpr-tooltip` instead.'
    );
  }

  /**
   * Icon name from the icon library
   */
  @Prop() icon: string = 'info';

  /**
   * Whether the tooltip is currently active/showing
   */
  @Prop() active: boolean = false;

  /*
   * Accessible label for the radio group
   */
  @Prop() ariaLabel: string;

  /*
   * Related tooltip id
   */
  @Prop() tooltipId: string;

  /**
   * Emitted when icon is clicked
   */
  @Event() tooltipIconClick: EventEmitter<void>;

  /**
   * Emitted when icon is hovered
   */
  @Event() tooltipIconHover: EventEmitter<void>;

  /**
   * Emitted when icon is hovered
   */
  @Event() tooltipIconLeave: EventEmitter<void>;

  private handleClick = (event: MouseEvent) => {
    event.stopPropagation();
    this.tooltipIconClick.emit();
  };

  private handleMouseEnter = () => {
    this.tooltipIconHover.emit();
  };

  private handleMouseLeave = () => {
    this.tooltipIconLeave.emit();
  };

  private handleFocus = () => {
    this.tooltipIconHover.emit();
  };

  private handleBlur = () => {
    this.tooltipIconLeave.emit();
  };

  private getButtonClasses(): string {
    const baseClasses =
      'rounded-full p-0 border-0 bg-transparent cursor-pointer transition-all duration-200 ease-in-out flex items-center justify-center';
    const stateClasses = this.active ? 'text-icon-actionable-focused' : 'text-icon-actionable-default';

    const hoverClasses = 'hover:text-icon-actionable-hover';
    const focusClasses =
      'focus:outline-none focus-visible:outline-focus focus-visible:outline-offset-2 focus-visible:outline-stroke-actionable-focused focus-visible:outline-solid';
    const activeClasses = 'active:text-icon-actionable-focused';

    return customTwMerge(baseClasses, stateClasses,  hoverClasses, focusClasses, activeClasses);
  }

  render() {
    return (
      <button
        class={this.getButtonClasses()}
        onClick={this.handleClick}
        onMouseEnter={this.handleMouseEnter}
        onMouseLeave={this.handleMouseLeave}
        onFocus={this.handleFocus}
        onBlur={this.handleBlur}
        aria-expanded={this.active ? 'true' : 'false'}
        type="button"
        aria-label={this.ariaLabel || 'tooltip icon'}
        aria-describedBy={this.tooltipId}
      >
        <slot>
          <wdpr-icon-library decorative icon={this.icon} size="small" />
        </slot>
      </button>
    );
  }
}
